"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[1183],{1(e,t,o){o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>a,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-2","title":"Discourses \u2014 Book 1, Chapter 2","description":"Book 1 \u2014 Chapter 2","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-2.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-2","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-2","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"sidebar_position":3,"title":"Discourses \u2014 Book 1, Chapter 2","sidebar_label":"Book 1, Ch. 2"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 1","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-1"},"next":{"title":"Book 1, Ch. 3","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-3"}}');var i=o(4848),n=o(8453);const a={sidebar_position:3,title:"Discourses \u2014 Book 1, Chapter 2",sidebar_label:"Book 1, Ch. 2"},r="Discourses",h={},l=[{value:"Book 1 \u2014 Chapter 2",id:"book-1--chapter-2",level:2},{value:"How One May Be True To One&#39;S Character In Everything",id:"how-one-may-be-true-to-ones-character-in-everything",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,n.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)("div",{style:{textAlign:"center"},children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,i.jsx)(t.h2,{id:"book-1--chapter-2",children:"Book 1 \u2014 Chapter 2"}),(0,i.jsx)(t.h3,{id:"how-one-may-be-true-to-ones-character-in-everything",children:"How One May Be True To One'S Character In Everything"})]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,i.jsxs)(o,{open:!0,children:[(0,i.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,i.jsxs)(t.p,{children:["The chapter opens with a provocative claim: the rational creature can endure anything ",(0,i.jsx)(t.em,{children:"rational"}),", and only the irrational is truly intolerable. What counts as rational, though, varies by person \u2014 which is exactly why education matters. It trains us to align our judgments with nature rather than mere habit or fear."]}),(0,i.jsxs)(t.p,{children:["The core argument is about ",(0,i.jsx)(t.strong,{children:"character as a personal standard"}),'. When facing a difficult choice, the question isn\'t just "what\'s the cost/benefit?" but "what does this do to who I am?" Epictetus is explicit: that part is yours to weigh, not his. Different men sell themselves at different prices.']}),(0,i.jsx)(t.p,{children:"The chapter is rich with examples:"}),(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Agrippinus"})," refuses to even deliberate about performing in Nero's shows \u2014 because the moment you start calculating, you've already compromised yourself."]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Priscus Helvidius"}),", ordered by Vespasian to stay out of the Senate, refuses: ",(0,i.jsx)(t.em,{children:'"You can forbid me to be a senator; but as long as I am one, I must come in."'})," He won't be silent, won't be spared, won't bargain. His value isn't in the outcome but in the act."]}),"\n",(0,i.jsxs)(t.li,{children:["An ",(0,i.jsx)(t.strong,{children:"Olympic athlete"})," chooses death over mutilation \u2014 not as a philosopher, but simply as a man who knows what he is."]}),"\n"]}),(0,i.jsxs)(t.p,{children:["The purple thread metaphor is the chapter's sharpest image: most people want to blend in, to be ordinary thread. Epictetus wants to be the purple \u2014 the one touch that gives the whole garment its distinction. Making yourself like the many destroys the very thing that makes you ",(0,i.jsx)(t.em,{children:"you"}),"."]}),(0,i.jsx)(t.p,{children:"The closing is deliberately modest. Not everyone is Socrates. Not every horse is swift. But that's no reason to stop. Epictetus doesn't claim to be Socrates \u2014 only to aim at it. The effort itself is the point."})]}),"\n",(0,i.jsxs)(o,{open:!0,children:[(0,i.jsx)("summary",{children:"Text"}),(0,i.jsx)(t.h2,{id:"text",children:"Text"}),(0,i.jsx)(t.p,{children:"TO THE rational creature that which is against reason is alone past bearing; the rational he can always bear. Blows are not by nature intolerable."}),(0,i.jsx)(t.p,{children:"'What do you mean?'"}),(0,i.jsx)(t.p,{children:"Let me explain; the Lacedaemonians bear flogging, because they have learnt that it is in accord with reason."}),(0,i.jsx)(t.p,{children:"'But is it not intolerable to hang oneself?'"}),(0,i.jsx)(t.p,{children:"At any rate, when a man comes to feel that it is rational, he goes and hangs himself at once. In a word, if we look to it we shall see that by nothing is the rational creature so distressed as by the irrational, and again to nothing so much attracted as to the rational."}),(0,i.jsx)(t.p,{children:"But rational and irrational mean different things to different persons,"}),(0,i.jsx)(t.p,{children:"just as good and evil, expedient and inexpedient, are different for different persons. That is the chief reason why we need education, that we may learn so to adjust our preconceptions  of rational and irrational to particular conditions as to be in harmony with nature. But to decide what is rational and irrational we not only estimate the value of things external, but each one of us considers what is in keeping with his character. For one man thinks it reasonable to perform the meanest office  for another; for he looks merely to this, that if he refuses he will be beaten and get no food, while if he does it nothing hard or painful will be done to him. To another it seems intolerable not only to do this service himself, but even to suffer another to do it. If then you ask me, 'Am I to do it or not?' I shall say to you, to get food is worth more than to go without it, and to be flogged is worth less than to escape flogging: therefore, if you measure your affairs by this standard, go and do it."}),(0,i.jsx)(t.p,{children:"'But I shall be false to myself.'"}),(0,i.jsx)(t.p,{children:"That is for you to bring into the question, not for me. For it is you who know yourself; you know at how much you put your worth, and at what price you sell yourself. For different men sell at different prices."}),(0,i.jsx)(t.p,{children:"That is why Agrippinus, when Florus was considering whether he should go down to Nero's shows, to perform some part in them himself, said to him, 'Go down.' And when he asked, 'Why do you not go down yourself?' said, 'Because I do not even consider the question.' For when a man once lowers himself to think about such matters, and to value external things and calculate about them he has almost forgotten his own character. What is it you ask me? 'Is death or life to be preferred?' I say 'life'. 'Pain or pleasure?' I say 'pleasure'."}),(0,i.jsx)(t.p,{children:"'But, if I do not act in the tragedy, I shall be beheaded.'"}),(0,i.jsx)(t.p,{children:"Go then and act your tragedy, but I will not do so. You ask me, 'Why?' I answer, 'Because you count yourself to be but an ordinary thread in the tunic.' What follows then? You ought to think how you can be like other men, just as one thread does not wish to have something special to distinguish it from the rest: but I want to be the purple, that touch of brilliance which gives distinction and beauty to the rest. Why then do you say to me, 'Make yourself like unto the many?' If I do that, I shall no longer be the purple."}),(0,i.jsx)(t.p,{children:"Priscus Helvidius too saw this, and acted on it. When Vespasian sent to him not to come into the Senate he answered, 'You can forbid me to be a senator; but as long as I am a senator I must come in.'"}),(0,i.jsx)(t.p,{children:"'Come in then,' he says, 'and be silent.'"}),(0,i.jsx)(t.p,{children:"'Question me not and I will be silent.'"}),(0,i.jsx)(t.p,{children:"'But I am bound to question you.'"}),(0,i.jsx)(t.p,{children:"'And I am bound to say what seems right to me.'"}),(0,i.jsx)(t.p,{children:"'But, if you say it, I shall kill you.'"}),(0,i.jsx)(t.p,{children:"'When did I tell you, that I was immortal? You will do your part, and I mine. It is yours to kill, mine to die without quailing: yours to banish, mine to go into exile without groaning.'"}),(0,i.jsx)(t.p,{children:"What good, you ask, did Priscus do, being but one? What good does the purple do to the garment? Just this, that being purple it gives distinction and stands out as a fine example to the rest. Another man, had Caesar in such circumstances told him not to come into the Senate, would have said, 'Thank you for sparing me.' Such a one he would never have forbidden to come in; he would know that he would either sit silent like a pipkin or if he spoke would say what he knew Caesar wished and pile on more besides."}),(0,i.jsx)(t.p,{children:"This spirit too was shown by a certain athlete, who was threatened with death if he did not sacrifice his virility. When his brother, who was a philosopher, came to him and said, 'Brother, what will you do? Are we to let the knife do its work and still go into the gymnasium?' he would not consent, but endured to meet his death. (Here some one asked, 'How did he do so, as an athlete or as a philosopher?')  He did so as a man, and a man who had wrestled at Olympia and been proclaimed victor, one who had passed his days in such a place as that, not one who anoints himself at Bato's. Another man would have consented to have even his head cut off, if he could have lived without it."}),(0,i.jsx)(t.p,{children:"That is what I mean by keeping your character: such is its power with those who have acquired the habit of carrying it into every question that arises."}),(0,i.jsx)(t.p,{children:"'Go to, Epictetus, have yourself shaved.'"}),(0,i.jsx)(t.p,{children:"If I am a philosopher I say, 'I will not be shaved.'"}),(0,i.jsx)(t.p,{children:"'I must behead you then.'"}),(0,i.jsx)(t.p,{children:"Behead me, if it is better for you so."}),(0,i.jsx)(t.p,{children:"One asked, 'How then shall we discover, each of us, what suits his character?'"}),(0,i.jsx)(t.p,{children:"How does the bull, he answered, at the lion's approach, alone discover what powers he is endowed with, when he stands forth to protect the whole herd? It is plain that with the possession of his power the consciousness of it also is given him. So each of us, who has power of this sort, will not be unaware of its possession. Like the bull, the man of noble nature does not become noble of a sudden; he must train through the winter, and make ready, and not lightly leap to meet things that concern him not."}),(0,i.jsx)(t.p,{children:"Of one thing beware, O man; see what is the price at which you sell your will. If you do nothing else, do not sell your will cheap. The great, heroic style, it may be, belongs to others, to Socrates and men like him."}),(0,i.jsx)(t.p,{children:"'If then this is our true nature, why do not all men, or many, show it?'"}),(0,i.jsx)(t.p,{children:"What? Do all horses turn out swift, are all dogs good at the scent?"}),(0,i.jsx)(t.p,{children:"'What am I to do then? Since I have no natural gifts, am I to make no effort for that reason?'"}),(0,i.jsx)(t.p,{children:"Heaven forbid. Epictetus is not better than Socrates: if only he is as good as Socrates I am content. For I shall never be a Milo, yet I do not neglect my body; nor a Croesus, and yet I do not neglect my property; nor, in a word, do we abandon our effort in any field because we despair of the first place."})]})]})}function c(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453(e,t,o){o.d(t,{R:()=>a,x:()=>r});var s=o(6540);const i={},n=s.createContext(i);function a(e){const t=s.useContext(n);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),s.createElement(n.Provider,{value:t},e.children)}}}]);